import{_ as e,o as a,c as o,a2 as r}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"皮特·利格尔","description":"","frontmatter":{"title":"皮特·利格尔"},"headers":[],"relativePath":"04_people/皮特·利格尔.md","filePath":"04_people/皮特·利格尔.md"}'),l={name:"04_people/皮特·利格尔.md"};function i(h,t,d,n,s,u){return a(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="皮特·利格尔-pete-liegel" tabindex="-1">皮特·利格尔（Pete Liegel） <a class="header-anchor" href="#皮特·利格尔-pete-liegel" aria-label="Permalink to &quot;皮特·利格尔（Pete Liegel）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>姓名</strong></td><td>Pete Liegel（皮特·利格尔）</td></tr><tr><td><strong>职位</strong></td><td>Forest River CEO / 创始人</td></tr><tr><td><strong>关联公司</strong></td><td>Forest River</td></tr><tr><td><strong>首次提及</strong></td><td>2005年</td></tr></tbody></table><h2 id="与巴菲特的故事" tabindex="-1">与巴菲特的故事 <a class="header-anchor" href="#与巴菲特的故事" aria-label="Permalink to &quot;与巴菲特的故事&quot;">​</a></h2><p>皮特·利格尔是Forest River的创始人兼CEO，他主动发传真给巴菲特促成收购，创造了伯克希尔收购史上最快速的交易之一。</p><h3 id="两页传真促成交易" tabindex="-1">两页传真促成交易 <a class="header-anchor" href="#两页传真促成交易" aria-label="Permalink to &quot;两页传真促成交易&quot;">​</a></h3><p>2005年6月21日，巴菲特收到一份来自陌生人的两页传真：</p><blockquote><p>&quot;几个月前的6月21日，我收到一份两页的传真，逐点告诉我Forest River如何符合本报告阐述的收购标准。我之前从未听说过这家公司——一家年销售额16亿美元的休闲房车制造商——也从未听说过其所有者兼经理皮特·利格尔。但这封传真说得很有道理，我立即要求提供更多数据。第二天早上数据就来了，当天下午我就向皮特报了价。6月28日，我们握手成交。&quot;（2005年股东信）</p></blockquote><p>从第一次联系到握手成交，仅用了<strong>8天</strong>。</p><h3 id="企业家精神" tabindex="-1">企业家精神 <a class="header-anchor" href="#企业家精神" aria-label="Permalink to &quot;企业家精神&quot;">​</a></h3><p>皮特的故事展现了非凡的企业家精神：</p><blockquote><p>&quot;皮特是一位非凡的企业家。几年前，他将当时远比现在小的公司卖给了LBO运营商，后者立刻开始告诉他如何经营。没过多久，皮特离开了，公司很快陷入破产。然后皮特把公司买回来了。你可以放心，我不会告诉皮特如何管理他的业务。&quot;（2005年股东信）</p></blockquote><h3 id="持续加速" tabindex="-1">持续加速 <a class="header-anchor" href="#持续加速" aria-label="Permalink to &quot;持续加速&quot;">​</a></h3><blockquote><p>&quot;Forest River拥有60家工厂、5,400名员工，在房车业务中持续获得市场份额，同时还扩展到船只等其他领域。皮特今年61岁——而且绝对处于加速模式。&quot;（2005年股东信）</p></blockquote><h3 id="信任管理" tabindex="-1">信任管理 <a class="header-anchor" href="#信任管理" aria-label="Permalink to &quot;信任管理&quot;">​</a></h3><p>巴菲特对皮特的管理能力给予了最高信任：</p><blockquote><p>&quot;Forest River拥有82家工厂，我还没有参观过任何一家（或者总部，就此而言）。没有必要；公司CEO皮特·利格尔经营着一家出色的企业。&quot;（2010年股东信）</p></blockquote><blockquote><p>&quot;Forest River，我们的房车和船只制造商，销售额创下近20亿美元的纪录，收益也创下纪录。&quot;（2010年股东信）</p></blockquote><h3 id="公开称赞" tabindex="-1">公开称赞 <a class="header-anchor" href="#公开称赞" aria-label="Permalink to &quot;公开称赞&quot;">​</a></h3><p>皮特曾在《华尔街日报》上公开称赞与伯克希尔的合作体验：</p><blockquote><p>&quot;把我的公司卖掉比续驾照还容易。&quot;（2005年《华尔街日报》引用）</p></blockquote><h2 id="关联年份" tabindex="-1">关联年份 <a class="header-anchor" href="#关联年份" aria-label="Permalink to &quot;关联年份&quot;">​</a></h2><p>2005, 2006, 2007, 2008, 2010</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../03_公司库/Forest_River.html">Forest River</a> - 管理的公司</li><li><a href="./../03_公司库/伯克希尔哈撒韦.html">伯克希尔·哈撒韦</a> - 母公司</li></ul><hr><p><em>最后更新：2026-04-09</em></p>',27)])])}const q=e(l,[["render",i]]);export{c as __pageData,q as default};
